6	  "type": "object",
7	  "additionalProperties": false,
8	  "required": ["version", "project", "pipeline", "phases"],
9	  "properties": {
10	    "version": {
11	      "type": "string",
12	      "const": "1",
13	      "description": "Schema version pin. Must be a quoted string '1' so YAML parsers don't coerce 1.10 → 1.1."
14	    },
15	    "project": {
16	      "type": "object",
17	      "additionalProperties": false,
18	      "required": ["name"],
19	      "properties": {
20	        "name": { "type": "string", "minLength": 1 }
21	      }
22	    },
23	    "pipeline": { "$ref": "#/$defs/pipeline" },
24	    "phases": {
25	      "type": "object",
