45	  "$defs": {
46	
47	    "pipeline": {
48	      "type": "object",
49	      "additionalProperties": false,
50	      "required": ["stages"],
51	      "description": "Pipeline structure using stages (Issue 1). Stage-to-stage flow is always sequential. Within a per-item stage, phase-to-phase transitions use the post: action grammar.",
52	      "properties": {
53	        "stages": {
54	          "type": "array",
55	          "minItems": 1,
