61	    "stage": {
62	      "type": "object",
63	      "additionalProperties": false,
64	      "required": ["id", "run", "phases"],
65	      "description": "A stage groups an ordered sequence of phases and declares whether they run once (per workflow) or per-item (per item in a manifest). Issue 1.",
66	      "properties": {
67	        "id": {
68	          "type": "string",
69	          "minLength": 1,
70	          "description": "Stable stage identifier. Unique within the pipeline."
71	        },
72	        "run": {
73	          "type": "string",
74	          "enum": ["once", "per-item"],
75	          "description": "once: phases run once for the workflow. per-item: phases run once per item from the manifest file (Issue 1)."
76	        },
77	        "phases": {
78	          "type": "array",
79	          "minItems": 1,
80	          "items": { "type": "string" },
81	          "description": "Ordered list of phase keys (references into the top-level phases map). Within a per-item stage, the post: action grammar applies to phase-to-phase transitions for the same item (Issue 1)."
82	        },
