{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://yoke.local/schemas/yoke-config.schema.json",
  "title": ".yoke.yml",
  "description": "User-authored configuration. Mirrors plan-draft3 §Configuration and the pre/post action grammar (§Phase Pre/Post Commands, D50, D53). Revised per beta3-review-feedback.md Issues 1–4: pipeline uses stages (not nodes+edges), items are opaque, review aggregation is user-owned. All object schemas set additionalProperties: false to fail fast on typos.",
  "type": "object",
  "additionalProperties": false,
  "required": ["version", "project", "pipeline", "phases"],
  "properties": {
    "version": {
      "type": "string",
      "const": "1",
      "description": "Schema version pin. Must be a quoted string '1' so YAML parsers don't coerce 1.10 → 1.1."
    },
    "project": {
      "type": "object",
      "additionalProperties": false,
      "required": ["name"],
      "properties": {
        "name": { "type": "string", "minLength": 1 }
      }
    },
    "pipeline": { "$ref": "#/$defs/pipeline" },
    "phases": {
      "type": "object",
      "minProperties": 1,
      "additionalProperties": { "$ref": "#/$defs/phase" }
    },
    "worktrees": { "$ref": "#/$defs/worktrees" },
    "notifications": { "$ref": "#/$defs/notifications" },
    "github": { "$ref": "#/$defs/github" },
    "retention": { "$ref": "#/$defs/retention" },
    "logging": { "$ref": "#/$defs/logging" },
    "runtime": { "$ref": "#/$defs/runtime" },
    "rate_limit": { "$ref": "#/$defs/rateLimit" },
    "ui": { "$ref": "#/$defs/ui" },
    "safety_mode": {
      "type": "string",
      "enum": ["strict", "default", "yolo"],
      "default": "default",
      "description": "Parameterizes the example safety hook template offered by yoke init. Advisory, not runtime-enforced (plan-draft3 §Threat Model, D51)."
    }
  },

  "$defs": {

    "pipeline": {
      "type": "object",
      "additionalProperties": false,
      "required": ["stages"],
      "description": "Pipeline structure using stages (Issue 1). Stage-to-stage flow is always sequential. Within a per-item stage, phase-to-phase transitions use the post: action grammar.",
      "properties": {
        "stages": {
          "type": "array",
          "minItems": 1,
          "items": { "$ref": "#/$defs/stage" }
        }
      }
    },

    "stage": {
      "type": "object",
      "additionalProperties": false,
      "required": ["id", "run", "phases"],
      "description": "A stage groups an ordered sequence of phases and declares whether they run once (per workflow) or per-item (per item in a manifest). Issue 1.",
      "properties": {
        "id": {
          "type": "string",
          "minLength": 1,
          "description": "Stable stage identifier. Unique within the pipeline."
        },
        "run": {
          "type": "string",
          "enum": ["once", "per-item"],
          "description": "once: phases run once for the workflow. per-item: phases run once per item from the manifest file (Issue 1)."
        },
        "phases": {
          "type": "array",
          "minItems": 1,
          "items": { "type": "string" },
          "description": "Ordered list of phase keys (references into the top-level phases map). Within a per-item stage, the post: action grammar applies to phase-to-phase transitions for the same item (Issue 1)."
        },
        "needs_approval": {
          "type": "boolean",
          "default": false,
          "description": "When true, the harness enters awaiting_user before starting this stage, requiring explicit user approval to proceed. Replaces the former edge-level needs_approval (Q-architecture-proposed-lifecycle)."
        },
        "items_from": {
          "type": "string",
          "description": "Path to the item manifest file, relative to the worktree. Required for per-item stages (Issue 2)."
        },
        "items_list": {
          "type": "string",
          "description": "JSONPath expression evaluated against items_from to extract the item array (Issue 2). E.g. '$.features'."
        },
        "items_id": {
          "type": "string",
          "description": "JSONPath expression evaluated per item to extract a stable string identifier (Issue 2). E.g. '$.id'."
        },
        "items_depends_on": {
          "type": "string",
          "description": "Optional JSONPath expression evaluated per item to extract an array of dependency item IDs for topological ordering (D08). If omitted, items are processed in manifest order with no dependency constraints."
        },
        "items_display": { "$ref": "#/$defs/itemsDisplay" }
      },
      "allOf": [
        {
          "if": { "properties": { "run": { "const": "per-item" } }, "required": ["run"] },
          "then": { "required": ["items_from", "items_list", "items_id"] }
        }
      ]
    },

    "itemsDisplay": {
      "type": "object",
      "additionalProperties": false,
      "description": "Dashboard rendering hints for items (Issue 2). If omitted, the dashboard shows the raw item ID.",
      "properties": {
        "title": {
          "type": "string",
          "description": "JSONPath expression per item for the dashboard row label."
        },
        "subtitle": {
          "type": "string",
          "description": "Optional JSONPath expression per item for secondary dashboard text."
        }
      }
    },

    "phase": {
      "type": "object",
      "additionalProperties": false,
      "required": ["command", "args", "prompt_template"],
      "properties": {
        "command": {
          "type": "string",
          "description": "Command to spawn. Default in docs is 'claude'; jig is one documented alternative but not required (D55)."
        },
        "args": {
          "type": "array",
          "items": { "type": "string" }
        },
        "env": {
          "type": "object",
          "additionalProperties": { "type": "string" }
